// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useCallback((payload: ActionSubmitPayload) => {
    console.log('Form submitted:', payload);
  }, []);

  // Form state — track all steps
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number | ''>('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = useCallback((value: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const isStep1Valid = useCallback(() => {
    return name.trim().length > 0 && email.trim().length > 0 && isValidEmail(email);
  }, [name, email, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return satisfaction !== '';
  }, [satisfaction]);

  // Navigation handlers
  const handleNext = useCallback(() => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep === 2 && !isStep2Valid()) return;
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: satisfaction as number,
      features,
      comments: comments.trim(),
    };
    submit(payload);
  }, [name, email, satisfaction, features, comments]);

  return {
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    comments,
    setComments,
    handleNext,
    handleBack,
    handleSubmit,
    isStep1Valid,
    isStep2Valid,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const {
    currentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    comments,
    setComments,
    handleNext,
    handleBack,
    handleSubmit,
    isStep1Valid,
    isStep2Valid,
  } = state;

  // Helper to toggle feature checkbox
  const toggleFeature = useCallback(
    (feature: string) => {
      setFeatures((prev) =>
        prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
      );
    },
    []
  );

  // Render step 1: Name & Email
  const renderStep1 = () => (
    <Stack gap={16}>
      <Heading level={3}>Your Information</Heading>
      <Input
        label="Name"
        value={name}
        onChange={setName}
        placeholder="Enter your full name"
        required
        error={name && name.trim().length === 0 && currentStep >= 1 ? 'Name is required' : undefined}
      />
      <Input
        label="Email"
        type="email"
        value={email}
        onChange={setEmail}
        placeholder="Enter your email address"
        required
        error={email && !isValidEmail(email) ? 'Please enter a valid email address' : undefined}
      />
    </Stack>
  );

  // Render step 2: Satisfaction Rating
  const renderStep2 = () => (
    <Stack gap={16}>
      <Heading level={3}>How satisfied are you?</Heading>
      <RadioGroup
        label="Satisfaction Rating"
        value={satisfaction !== '' ? String(satisfaction) : ''}
        onChange={(val) => setSatisfaction(Number(val))}
        options={(props.satisfactionLabels || []).map((label, idx) => ({
          value: String(idx + 1),
          label: label,
        }))}
      />

  // Render step 3: Feature Interests
  const renderStep3 = () => (
    <Stack gap={16}>
      <Heading level={3}>Which features interest you?</Heading>
      <Stack gap={8}>
        {(props.featureOptions || []).map((feature) => (
          <Checkbox
            key={feature}
            label={feature}
            checked={features.includes(feature)}
            onChange={(checked) => {
              if (checked) {
                setFeatures((prev) => [...prev, feature]);
              } else {
                setFeatures((prev) => prev.filter((f) => f !== feature));
              }
            }}
          />
        ))}
      </Stack>
    </Stack>
  );

  // Render step 4: Comments
  const renderStep4 = () => (
    <Stack gap={16}>
      <Heading level={3}>Additional Comments</Heading>
      <TextArea
        label="Comments"
        value={comments}
        onChange={setComments}
        placeholder="Tell us anything else you'd like to share (optional)"
        maxLength={500}
        showCount
        rows={6}
      />
    </Stack>
  );

  // Render review step
  const renderReview = () => (
    <Stack gap={16}>
      <Heading level={3}>Review Your Answers</Heading>
      <Card shadow="sm" padding={16} border>
        <Stack gap={12}>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
            <Text>{name}</Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
            <Text>{email}</Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
            <Text>{satisfaction && typeof satisfaction === 'number' && satisfaction > 0 ? props.satisfactionLabels[satisfaction - 1] : 'Not selected'}</Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features of Interest</Text>
            <Stack gap={4} direction="horizontal" wrap>
              {features.length > 0 ? (
                features.map((feature) => (
                  <Badge key={feature} variant="primary" size="sm">
                    {feature}
                  </Badge>
                ))
              ) : (
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  None selected
                </Text>
              )}
            </Stack>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
            <Text>{comments || '(No additional comments)'}</Text>
          </Box>
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={1}>Multi-Step Survey</Heading>
          <Progress
             max={5},
            variant="default"
            size="md"
            showLabel
          />
        </Stack>

        {/* Form Content */}
        <Card shadow="md" padding={24} radius="lg" border={false}>
          {currentStep === 1 && renderStep1()}
          {currentStep === 2 && renderStep2()}
          {currentStep === 3 && renderStep3()}
          {currentStep === 4 && renderStep4()}
          {currentStep === 5 && renderReview()}
        </Card>

        {/* Navigation */}
        <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 5
          </Text>
          {currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={
                (currentStep === 1 && !isStep1Valid()) ||
                (currentStep === 2 && !isStep2Valid())
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}

