import React, { useState, useCallback, useRef, useEffect } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const handleTaskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'taskUpdate', payload } }));
  };

  // Streams — real-time from agent (listen via window event)
  const [streamData, setStreamData] = useState<StreamTaskChanged | null>(null);

  const [tasks, setTasks] = useState(props.tasks || []);
  const [newTaskColumn, setNewTaskColumn] = useState('todo');
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTaskTitle, setEditingTaskTitle] = useState('');
  const [showAddForm, setShowAddForm] = useState<string | null>(null);

  // Update local tasks when stream events arrive
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamTaskChanged>;
      const taskEvent = customEvent.detail;
      if (taskEvent?.task) {
        setTasks((prev) => {
          if (taskEvent.action === 'delete' && taskEvent.task?.id) {
            return prev.filter((t) => t.id !== taskEvent.task?.id);
          }
          if (taskEvent.action === 'create' && taskEvent.task?.id) {
            if (!prev.find((t) => t.id === taskEvent.task?.id)) {
              return [...prev, taskEvent.task];
            }
          }
          if (taskEvent.action === 'move' || taskEvent.action === 'edit') {
            return prev.map((t) => (t.id === taskEvent.task?.id ? { ...t, ...taskEvent.task } : t));
          }
          return prev;
        });
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t))
      );
      handleTaskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [handleTaskUpdate]
  );

  const handleEditTaskTitle = useCallback(
    (taskId: string, newTitle: string) => {
      if (newTitle.trim()) {
        setTasks((prev) =>
          prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
        );
        handleTaskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' } });
      }
      setEditingTaskId(null);
      setEditingTaskTitle('');
    },
    [handleTaskUpdate, tasks]
  );

  const handleAddTask = useCallback(
    (columnId: string) => {
      if (newTaskTitle.trim()) {
        const newId = `task-${Date.now()}`;
        const newTask = {
          id: newId,
          title: newTaskTitle,
          priority: newTaskPriority,
          column: columnId,
          assignee: '',
          dueDate: '',
        };
        setTasks((prev) => [...prev, newTask]);
        handleTaskUpdate({ action: 'create', taskId: newId, data: { column: columnId } });
        setNewTaskTitle('');
        setNewTaskPriority('medium');
        setShowAddForm(null);
      }
    },
    [newTaskTitle, newTaskPriority, handleTaskUpdate]
  );

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  return {
    tasks,
    setTasks,
    newTaskColumn,
    setNewTaskColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    setEditingTaskId,
    editingTaskTitle,
    setEditingTaskTitle,
    showAddForm,
    setShowAddForm,
    handleMoveTask,
    handleEditTaskTitle,
    handleAddTask,
    totalTasks,
    completedTasks,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Priority color mapping
  const priorityColors: { [key in 'low' | 'medium' | 'high']: string } = {
    low: 'var(--ggui-color-info-600, #0284c7)',
    medium: 'var(--ggui-color-warning-600, #d97706)',
    high: 'var(--ggui-color-error-600, #dc2626)',
  };

  return (
    <Container maxWidth='3xl' padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Box background='var(--ggui-color-primary-50, #f0f9ff)' padding={16} borderRadius={8}>
          <Row justify='between' align='center'>
            <Stack direction='horizontal' gap={16}>
              <Stack gap={4}>
                <Text variant='label' color='var(--ggui-color-primary-600, #0284c7)'>Total Tasks</Text>
                <Heading level={3}>{state.totalTasks}</Heading>
              </Stack>
              <Divider orientation='vertical' margin={0} />
              <Stack gap={4}>
                <Text variant='label' color='var(--ggui-color-success-600, #16a34a)'>Completed</Text>
                <Heading level={3}>{state.completedTasks}</Heading>
              </Stack>
            </Stack>
          </Row>
        </Box>

        {/* Kanban Board */}
         <Row gap={16} align='start' wrap={true}>
          {props.columns.map((column) => {
            const columnTasks = state.tasks.filter((t) => t.column === column.id);

            return (
              <Box
                key={column.id}
                style={{
                  flex: '0 1 320px',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  padding: 'var(--ggui-spacing-4, 16px)',
                  minHeight: '500px',
                  display: 'flex',
                  flexDirection: 'column',
                }}
              >
                {/* Column Header */}
                <Stack gap={8} style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                  <Row justify='between' align='center'>
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant='secondary' size='sm'>{columnTasks.length}</Badge>
                  </Row>
                  <Divider orientation='horizontal' margin={0} />
                </Stack>

                {/* Task List */}
                <Stack gap={12} style={{ flex: 1, overflowY: 'auto', marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                  {columnTasks.map((task) => (
                    <Card key={task.id} shadow='sm' padding={12} radius='md'>
                      <Stack gap={8}>
                        {/* Task Title */}
                        {state.editingTaskId === task.id ? (
                           <Input
                             label='Edit task'
                             value={state.editingTaskTitle}
                             onChange={state.setEditingTaskTitle}
                             onKeyDown={(e: any) => {
                               if (e.key === 'Enter') state.handleEditTaskTitle(task.id!, state.editingTaskTitle);
                               if (e.key === 'Escape') { state.setEditingTaskId(null); state.setEditingTaskTitle(''); }
                             }}
                             placeholder='Task title'
                             size='sm'
                           />
                        ) : (
                          <Text
                            as={Clickable}
                            onClick={() => {
                              state.setEditingTaskId(task.id!);
                              state.setEditingTaskTitle(task.title || '');
                            }}
                            variant='body'
                            weight='semibold'
                            style={{ cursor: 'pointer' }}
                          >
                            {task.title}
                          </Text>
                        )}

                        {/* Priority & Assignee Row */}
                        <Row gap={8} justify='start' align='center'>
                          {task.priority && (
                            <Badge
                              variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}
                              size='sm'
                            >
                              {task.priority}
                            </Badge>
                          )}
                          {task.assignee && (
                            <Avatar name={task.assignee} size='xs' />
                          )}
                        </Row>

                        {/* Due Date */}
                        {task.dueDate && (
                          <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                            Due: {new Date(task.dueDate).toLocaleDateString()}
                          </Text>
                        )}

                        {/* Move Controls */}
                        <Dropdown
                          trigger={<Button variant='outline' size='xs'>Move</Button>}
                          options={props.columns
                            .filter((c) => c.id !== column.id)
                            .map((c) => ({
                              value: c.id!,
                              label: `Move to ${c.name}`,
                            }))
                          }
                          value=''
                          onChange={(value) => state.handleMoveTask(task.id!, value)}
                          placement='bottom-start'
                        />
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {/* Add Task Button / Form */}
                {state.showAddForm === column.id ? (
                  <Card shadow='sm' padding={12} radius='md' border={true}>
                    <Stack gap={8}>
                      <Input
                        label='Task title'
                        value={state.newTaskTitle}
                        onChange={state.setNewTaskTitle}
                        placeholder='Enter task title'
                        size='sm'
                      />
                      <Select
                        label='Priority'
                        value={state.newTaskPriority}
                        onChange={(value) => state.setNewTaskPriority(value as 'low' | 'medium' | 'high')}
                        options={[
                          { value: 'low', label: 'Low' },
                          { value: 'medium', label: 'Medium' },
                          { value: 'high', label: 'High' },
                        ]}
                        size='sm'
                      />
                      <Row gap={8} justify='end'>
                        <Button
                          variant='ghost'
                          size='sm'
                          onClick={() => {
                            state.setShowAddForm(null);
                            state.setNewTaskTitle('');
                            state.setNewTaskPriority('medium');
                          }}
                        >
                          Cancel
                        </Button>
                        <Button
                          variant='primary'
                          size='sm'
                          onClick={() => state.handleAddTask(column.id!)}
                        >
                          Add
                        </Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button
                    variant='ghost'
                    fullWidth={true}
                    onClick={() => state.setShowAddForm(column.id!)}
                  >
                    + Add Task
                  </Button>
                )}
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

