import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = async (payload: ActionCompletePayload) => { console.log('Complete:', payload); };

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? '',
    role: props.initialProfile?.role ?? '',
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? 'light',
  });

  // Validation
  const isValidEmail = useCallback((email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }, []);

  const isStep1Valid = useCallback(() => {
    return formData.name.trim().length > 0 && isValidEmail(formData.email) && formData.avatar.length > 0;
  }, [formData, isValidEmail]);

  const isStep2Valid = useCallback(() => {
    return formData.role.length > 0;
  }, [formData]);

  // Handlers
  const handleFieldChange = useCallback((field: string, value: string | boolean) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1 && isStep1Valid()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid()) {
      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    if (formData.name && isValidEmail(formData.email) && formData.avatar && formData.role) {
      complete({
        name: formData.name,
        email: formData.email,
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    }
  }, [formData, isValidEmail, complete]);

  return { currentStep, setCurrentStep, formData, handleFieldChange, handleNext, handleBack, handleComplete, isStep1Valid, isStep2Valid };
}

export default function Component(props: Props) {
  const state = useComponent(props);
  const { currentStep, formData, handleFieldChange, handleNext, handleBack, handleComplete, isStep1Valid, isStep2Valid } = state;

  const totalSteps = 3;
  const progressPercent = (currentStep / totalSteps) * 100;

  // Validate email format
  const emailError = formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) ? 'Please enter a valid email address' : '';
  const nameError = !formData.name.trim() ? 'Name is required' : '';

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={16}>
          <Heading level={2}>Create Your Profile</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of {totalSteps}
          </Text>

          {/* Progress Bar */}
          <Box
            background="var(--ggui-color-outlineVariant, #e4e4e7)"
            borderRadius={8}
            paddingY={0}
            paddingX={0}
            style={{ height: '4px', overflow: 'hidden' }}
          >
            <Box
              background="var(--ggui-color-primary-600, #0284c7)"
              style={{
                width: `${progressPercent}%`,
                height: '100%',
                transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
              }}
            />
          </Box>
        </Stack>
        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Profile Setup</Heading>

              <Input
                label="Full Name"
                value={formData.name}
                onChange={(value) => handleFieldChange('name', value)}
                placeholder="Enter your full name"
                error={nameError}
              />

              <Input
                label="Email Address"
                type="email"
                value={formData.email}
                onChange={(value) => handleFieldChange('email', value)}
                placeholder="you@example.com"
                error={emailError}
              />

              <Stack gap={8}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Choose Avatar
                </Text>
                <Row gap={16} align="center">
                  {props.avatarOptions.map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      onClick={() => handleFieldChange('avatar', emoji)}
                      style={{
                        fontSize: '2rem',
                        cursor: 'pointer',
                        padding: 8,
                        borderRadius: 8,
                        border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid transparent',
                        transition: 'all 200ms ease-in-out',
                      }}
                      hoverStyle={{
                        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                      }}
                    >
                      {emoji}
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}
        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>

              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => handleFieldChange('role', value)}
                options={props.roleOptions.map(role => ({ value: role, label: role }))}
                placeholder="Select your role"
              />

              <Row gap={8} align="center" justify="between">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Email Notifications
                </Text>
                <Toggle
                  label=""
                  checked={formData.emailNotifications}
                  onChange={(value) => handleFieldChange('emailNotifications', value)}
                  size="md"
                />
              </Row>

              <Row gap={8} align="center" justify="between">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Dark Theme
                </Text>
                <Toggle
                  label=""
                  checked={formData.theme === 'dark'}
                  onChange={(value) => handleFieldChange('theme', value ? 'dark' : 'light')}
                  size="md"
                />
              </Row>
             </Stack>
           </Card>
        )}
        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Review Your Information</Heading>

              {/* Summary Section */}
              <Box background="var(--ggui-color-primary-50, #f0f9ff)" borderRadius={8} padding={16}>
                <Stack gap={12}>
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Name</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">{formData.name}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Email</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">{formData.email}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Avatar</Text>
                    <Text style={{ fontSize: '1.5rem' }}>{formData.avatar}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Role</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">{formData.role}</Text>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Email Notifications</Text>
                    <Badge variant={formData.emailNotifications ? 'success' : 'default'}>
                      {formData.emailNotifications ? 'Enabled' : 'Disabled'}
                    </Badge>
                  </Stack>
                  <Divider />
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)">Theme</Text>
                    <Text color="var(--ggui-color-onSurface, #18181b)">{formData.theme === 'dark' ? 'Dark' : 'Light'}</Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Card>
        )}
        {/* Navigation Buttons */}
        <Row gap={8} justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Go Back
          </Button>

          {currentStep < totalSteps ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={currentStep === 1 ? !isStep1Valid() : !isStep2Valid()}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
